import{l as e,a as i,c as t,a6 as a}from"./chunks/framework.C0d1FTMf.js";const k=JSON.parse('{"title":"d.ts 自动引用","description":"","frontmatter":{},"headers":[],"relativePath":"interview/dts_auto_imprt.md","filePath":"interview/dts_auto_imprt.md"}'),o={name:"interview/dts_auto_imprt.md"};function n(p,s,d,c,l,h){return i(),t("div",null,[...s[0]||(s[0]=[a('<h1 id="d-ts-自动引用" tabindex="-1">d.ts 自动引用 <a class="header-anchor" href="#d-ts-自动引用" aria-label="Permalink to &quot;d.ts 自动引用&quot;">​</a></h1><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">typescript 中，为何有些 d.ts 文件能自动被全局自动引用</span></span></code></pre></div><p>在 TypeScript 中，有些 <code>.d.ts</code>（类型声明）文件能够被全局自动引用，主要是由 <strong>“TypeScript 的模块机制”</strong> 和 <strong>“编译器的文件发现规则”</strong> 共同决定的。 具体来说，有以下几个核心原因：</p><h3 id="_1-文件内没有顶层的-import-或-export-最核心原因" tabindex="-1">1. 文件内没有顶层的 <code>import</code> 或 <code>export</code>（最核心原因） <a class="header-anchor" href="#_1-文件内没有顶层的-import-或-export-最核心原因" aria-label="Permalink to &quot;1. 文件内没有顶层的 `import` 或 `export`（最核心原因）&quot;">​</a></h3><p>在 TypeScript 中，判断一个文件是“模块”还是“全局脚本”的唯一标准是：<strong>该文件中是否存在顶层的 <code>import</code> 或 <code>export</code> 关键字。</strong></p><ul><li><strong>全局脚本文件：</strong> 如果一个 <code>.d.ts</code> 文件中<strong>没有任何</strong>顶层 <code>import</code> 或 <code>export</code>（即使在 <code>declare global</code> 之外），TypeScript 就会把它当作全局脚本文件。它里面声明的所有类型、变量都会自动挂载到全局作用域中。<div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// global.d.ts</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">declare</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> myGlobalVar</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 全局可用，无需 import</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Window</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  myCustomProp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 全局可用，无需 import</span></span></code></pre></div></li><li><strong>模块文件：</strong> 如果一个 <code>.d.ts</code> 文件哪怕只有一行 <code>export {}</code>，它就变成了一个模块。它里面的声明就不会污染全局，必须通过 <code>import</code> 才能使用。</li></ul><h3 id="_2-tsconfig-json-中的-include-配置" tabindex="-1">2. <code>tsconfig.json</code> 中的 <code>include</code> 配置 <a class="header-anchor" href="#_2-tsconfig-json-中的-include-配置" aria-label="Permalink to &quot;2. `tsconfig.json` 中的 `include` 配置&quot;">​</a></h3><p>TypeScript 编译器需要知道去哪里找这些文件。如果你的 <code>tsconfig.json</code> 配置了 <code>include</code>，并且匹配到了这些全局 <code>.d.ts</code> 文件，它们就会被编译器自动加载。</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;compilerOptions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;include&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/**/*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;types/**/*.d.ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>只要 <code>types</code> 目录下的 <code>.d.ts</code> 符合“全局脚本文件”的特征，它们里面的类型就会被全局自动注入。</p><h3 id="_3-默认的-types-自动加载机制" tabindex="-1">3. 默认的 <code>@types</code> 自动加载机制 <a class="header-anchor" href="#_3-默认的-types-自动加载机制" aria-label="Permalink to &quot;3. 默认的 `@types` 自动加载机制&quot;">​</a></h3><p>TypeScript 默认会自动将 <code>node_modules/@types</code> 目录下的所有包引入到项目中。 例如，当你安装了 <code>@types/node</code> 后，你不需要在代码里写 <code>import { process } from &#39;node&#39;</code> 就能直接使用 <code>process</code>。 这是因为 <code>@types/node</code> 中的某些 <code>.d.ts</code> 文件被定义为了全局脚本文件，并且 TypeScript 默认会扫描 <code>node_modules/@types</code> 目录，将这些全局声明自动挂载。</p><blockquote><p>你可以通过 <code>tsconfig.json</code> 中的 <code>types</code> 选项来控制这一行为。如果不配置 <code>types</code>，TS 会自动包含 <code>@types</code> 下的所有内容；如果配置了 <code>types: [&quot;node&quot;]</code>，则只会自动引入 node 的类型。</p></blockquote><h3 id="_4-npm-包-package-json-中的-types-typings-字段" tabindex="-1">4. NPM 包 <code>package.json</code> 中的 <code>types</code>/<code>typings</code> 字段 <a class="header-anchor" href="#_4-npm-包-package-json-中的-types-typings-字段" aria-label="Permalink to &quot;4. NPM 包 `package.json` 中的 `types`/`typings` 字段&quot;">​</a></h3><p>当你在项目中 <code>npm install</code> 一个第三方库时，如果这个库的 <code>package.json</code> 中配置了 <code>types</code> 或 <code>typings</code> 字段指向了一个 <code>.d.ts</code> 文件，TypeScript 就会自动识别这个类型声明文件。 如果这个包的类型文件本身是通过“全局脚本”的方式编写的（虽然现代库很少这么做，但在早期 jQuery 等库很常见），那么只要项目依赖了它，它的类型就会自动全局可用。</p><h3 id="_5-三斜线指令" tabindex="-1">5. 三斜线指令 <a class="header-anchor" href="#_5-三斜线指令" aria-label="Permalink to &quot;5. 三斜线指令&quot;">​</a></h3><p>这是一种较老但仍被支持的机制。在一个 <code>.d.ts</code> 文件或普通 <code>.ts</code> 文件顶部，可以通过三斜线指令显式地告诉编译器去引入其他依赖的类型：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/// &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">reference</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> types</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;node&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /&gt;</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/// &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">reference</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> path</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;../types/my-custom.d.ts&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /&gt;</span></span></code></pre></div><h2 id="一旦编译器遇到这个指令-就会把对应的类型声明文件拉进来。如果被引入的文件又是全局脚本格式-那么它的类型也就全局可用了。" tabindex="-1">一旦编译器遇到这个指令，就会把对应的类型声明文件拉进来。如果被引入的文件又是全局脚本格式，那么它的类型也就全局可用了。 <a class="header-anchor" href="#一旦编译器遇到这个指令-就会把对应的类型声明文件拉进来。如果被引入的文件又是全局脚本格式-那么它的类型也就全局可用了。" aria-label="Permalink to &quot;一旦编译器遇到这个指令，就会把对应的类型声明文件拉进来。如果被引入的文件又是全局脚本格式，那么它的类型也就全局可用了。&quot;">​</a></h2><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>简单来说，一个 <code>.d.ts</code> 能被全局自动引用，必须同时满足两个条件：</p><ol><li><strong>编译器能找到它</strong>（通过 <code>include</code>、<code>@types</code> 默认机制、或 <code>reference</code> 指令）。</li><li><strong>文件内没有顶层 <code>export</code>/<code>import</code></strong>，使其被判定为全局脚本。 <strong>最佳实践提示：</strong> 虽然全局自动引用很方便，但现代 TypeScript 开发<strong>强烈推荐使用模块化（ES Modules）</strong>，即在 <code>.d.ts</code> 文件中通过 <code>export</code> 导出类型，在使用的地方通过 <code>import</code> 引入。这样可以避免全局命名冲突，让类型依赖关系更加清晰，也有利于 Tree-shaking 和长期维护。仅对一些不可避免的全局变量（如扩展 <code>Window</code>、注入到 HTML 中的第三方 SDK）才使用全局 <code>.d.ts</code>。</li></ol>',22)])])}const g=e(o,[["render",n]]);export{k as __pageData,g as default};
